{
  "domain_analysis": {
    "business_context": "A global logistics platform is building a driver earnings transparency feature that must comply with three distinct regulatory regimes: California (AB5 employee classification with mandated wage transparency), Germany (works council co-determination rights over compensation display), and Indonesia (independent contractor model with no transparency mandate). The feature must show base pay, per-delivery bonus, tips, and deductions in real time.",
    "bounded_context": "Driver Compensation & Earnings Visibility",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The fixed compensation component a driver receives independent of delivery volume, applicable primarily to employee-classified drivers (California)." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation tied to each completed delivery, applicable across all markets." },
      { "term": "Tips", "definition": "Gratuities from customers passed through to drivers, subject to jurisdiction-specific rules on visibility and handling." },
      { "term": "Deductions", "definition": "Amounts subtracted from gross earnings — nature varies by jurisdiction (tax withholding, benefits, equipment fees, platform fees, etc.)." },
      { "term": "Earnings Breakdown", "definition": "An itemized view of all compensation components and deductions for a given period." },
      { "term": "Real Time", "definition": "Ambiguous — could mean per-delivery instant update, periodic refresh (e.g., every 15 minutes), or end-of-shift summary." },
      { "term": "Works Council (Betriebsrat)", "definition": "A German employee co-determination body with legally mandated approval rights over changes to systems that display or affect compensation." },
      { "term": "AB5 Classification", "definition": "California law (Assembly Bill 5) that classifies most gig workers as employees, triggering wage transparency and labor law obligations." },
      { "term": "Driver Classification", "definition": "The legal status of a driver — employee or independent contractor — which determines which compensation rules, tax obligations, and transparency requirements apply." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Every driver must see an itemized earnings breakdown containing at minimum: base pay, per-delivery bonus, tips, and deductions.",
      "invariant": true,
      "invariant_justification": "This is the core feature requirement. Without all four components, the breakdown is incomplete and potentially misleading, which in regulated markets constitutes a compliance violation.",
      "testable_assertion": "For any driver in any market, the earnings breakdown view contains distinct line items for base pay, per-delivery bonus, tips, and deductions."
    },
    {
      "id": "BR-2",
      "rule": "In California, the earnings breakdown must comply with AB5 wage transparency requirements, meaning drivers classified as employees must receive wage statement information equivalent to what California Labor Code §226 mandates.",
      "invariant": true,
      "invariant_justification": "Legal compliance is non-negotiable. Failure to provide mandated wage information to AB5-classified employees exposes the platform to penalties and lawsuits.",
      "testable_assertion": "A California driver's earnings breakdown includes all fields required by California Labor Code §226 (hours worked, rates of pay, gross/net wages, deductions itemized by type, pay period dates)."
    },
    {
      "id": "BR-3",
      "rule": "In Germany, the compensation display feature must NOT be rolled out to drivers until the applicable works council (Betriebsrat) has formally approved the system.",
      "invariant": true,
      "invariant_justification": "German co-determination law (BetrVG §87) gives works councils mandatory co-determination rights over compensation-related monitoring systems. Deploying without approval is illegal and can result in injunctions.",
      "testable_assertion": "The feature is gated behind a jurisdiction-level feature flag; Germany's flag cannot be enabled without a recorded works council approval event."
    },
    {
      "id": "BR-4",
      "rule": "Deductions shown must be itemized by category, not presented as a single lump sum.",
      "invariant": false,
      "invariant_justification": "A lump-sum deduction display would undermine transparency — the stated goal of the feature — and in California would violate wage statement requirements. However, the specific categories may vary by jurisdiction and could be updated by policy.",
      "testable_assertion": "The deductions section displays each deduction as a separate line item with a label and amount; no single 'Total Deductions' line appears without underlying detail."
    },
    {
      "id": "BR-5",
      "rule": "Tips must be displayed separately from platform-determined compensation and must never be reduced by or commingled with deductions.",
      "invariant": true,
      "invariant_justification": "In California, tip misappropriation is illegal under Labor Code §351. Commingling tips with deductions would create the appearance of tip skimming, a legal and reputational catastrophe in any market.",
      "testable_assertion": "The tips line item is always shown independently; no deduction line item references tips; gross tips equal the sum of customer-entered tip amounts for the period."
    },
    {
      "id": "BR-6",
      "rule": "The earnings breakdown must be scoped to the driver's legal classification in their operating jurisdiction — employee-specific fields (hours worked, hourly rate, benefits deductions) must appear for employees and must NOT appear for independent contractors.",
      "invariant": true,
      "invariant_justification": "Displaying employee-specific fields to contractors (or vice versa) creates misclassification risk. If a contractor sees 'hourly rate' and 'hours worked,' it implies an employment relationship, which is legally dangerous for the platform.",
      "testable_assertion": "An Indonesian contractor's earnings view does not contain 'hours worked' or 'hourly rate' fields. A California employee's view includes both."
    },
    {
      "id": "BR-7",
      "rule": "Earnings data must reflect the driver's current state — not stale or batch-processed data beyond the defined freshness threshold.",
      "invariant": false,
      "invariant_justification": "The spec says 'real time' but the exact freshness threshold is a tunable business policy, not a physical constraint. What matters is that whatever threshold is defined, the system honors it.",
      "testable_assertion": "After a delivery is marked complete, the driver's earnings breakdown reflects the new delivery's compensation within the defined freshness SLA."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California completes a delivery",
      "when": "The driver opens their earnings breakdown",
      "then": "They see itemized base pay, per-delivery bonus, tips, and deductions (each deduction labeled by type), along with hours worked, hourly rate, gross wages, net wages, and pay period — consistent with California Labor Code §226"
    },
    {
      "id": "AC-2",
      "given": "The German works council has NOT yet approved the compensation display system",
      "when": "A driver in Germany attempts to access the earnings breakdown",
      "then": "The feature is unavailable (hidden or gracefully blocked with an explanation), and no compensation data is displayed through this new feature"
    },
    {
      "id": "AC-3",
      "given": "The German works council HAS formally approved the system",
      "when": "An operator enables the Germany feature flag with the recorded approval reference",
      "then": "German drivers can access the earnings breakdown with all required fields"
    },
    {
      "id": "AC-4",
      "given": "A driver in Indonesia (independent contractor) completes a delivery",
      "when": "The driver opens their earnings breakdown",
      "then": "They see per-delivery bonus, tips, and any platform fees or deductions — but do NOT see employee-specific fields like hourly rate, hours worked, or benefits deductions"
    },
    {
      "id": "AC-5",
      "given": "A driver has received tips on three deliveries today",
      "when": "The driver views their earnings breakdown",
      "then": "The tips total equals the exact sum of customer-entered tip amounts, displayed as its own line item, not netted against any deduction"
    },
    {
      "id": "AC-6",
      "given": "A driver has deductions applied (tax withholding, platform fees, etc.)",
      "when": "The driver views the deductions section",
      "then": "Each deduction is listed individually with its category label and amount — no opaque lump sum"
    },
    {
      "id": "AC-7",
      "given": "A delivery was completed moments ago",
      "when": "The driver refreshes their earnings view",
      "then": "The new delivery's earnings appear within the defined freshness SLA, not deferred to a next-day batch"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver relocates from Indonesia to California mid-employment",
      "expected_behavior": "The earnings breakdown must transition to the California employee template (adding hours worked, hourly rate, wage statement compliance fields) from the effective date of reclassification. Historical earnings in Indonesia remain under the contractor view."
    },
    {
      "scenario": "A California driver completes a delivery but the tip is adjusted (increased or removed) by the customer after initial display",
      "expected_behavior": "The earnings breakdown must update to reflect the final tip amount. A real-time display showing a tip that is later reduced creates confusion; the system must either show tips only after finalization or clearly mark pending tips as provisional."
    },
    {
      "scenario": "A delivery results in zero or negative net earnings after deductions",
      "expected_behavior": "The breakdown must still show all line items transparently. The system must never hide deductions that result in zero/negative net pay — this is especially critical under California wage transparency law."
    },
    {
      "scenario": "The works council in Germany requests modifications to the display format as a condition of approval",
      "expected_behavior": "The system must support jurisdiction-specific display customization. Germany's layout may differ from California's or Indonesia's per works council requirements without breaking the core data model."
    },
    {
      "scenario": "A driver works across two jurisdictions in the same day (e.g., cross-border in the EU)",
      "expected_behavior": "Earnings should be segmented by jurisdiction to ensure each segment complies with its local rules. Commingling cross-border earnings into one view risks applying the wrong legal template."
    },
    {
      "scenario": "Platform fees are introduced as a new deduction category not previously shown",
      "expected_behavior": "The deductions model must be extensible — new deduction types can be added without code changes. Each new type must be labeled and individually visible, never silently folded into existing categories."
    }
  ],

  "business_impact": {
    "financial": "Non-compliance with AB5 wage statement rules carries penalties of $50-$4,000 per employee per pay period under California Labor Code §226. Works council violations in Germany can result in court injunctions halting operations. The feature itself drives driver trust, which correlates with retention — even a 5% improvement in retention saves significant recruitment costs at scale.",
    "operational": "The feature requires jurisdiction-aware rendering logic, a works council approval workflow gate, and a classification-aware field mapping. This adds operational complexity to every new market launch — each jurisdiction needs a compliance review before feature enablement.",
    "user": "Drivers gain visibility into how they are compensated, building trust and reducing support tickets about pay discrepancies. However, if deductions are unexpectedly high or poorly explained, the feature could increase driver dissatisfaction and churn.",
    "risk": "HIGH. Three distinct legal regimes mean three distinct failure modes. California non-compliance is the highest immediate risk (statutory penalties, class action exposure). Germany non-compliance can halt the feature entirely via injunction. Indonesia is lowest risk legally but reputational damage from poor transparency still applies.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Gain legally mandated wage transparency; may surface previously invisible deduction patterns" },
      { "group": "Drivers (Germany)", "impact": "Feature delayed until works council approval; must not feel disadvantaged relative to other markets" },
      { "group": "Drivers (Indonesia)", "impact": "Gain voluntary transparency; contractor-appropriate view must not imply employment relationship" },
      { "group": "Legal/Compliance Team", "impact": "Must validate each jurisdiction's display fields before launch; ongoing obligation as laws change" },
      { "group": "German Works Council", "impact": "Gains co-determination authority over feature; must be engaged early or rollout is blocked" },
      { "group": "Product/Engineering", "impact": "Must build jurisdiction-aware, classification-aware display logic with feature gating" },
      { "group": "Finance/Payroll", "impact": "Must provide real-time earnings data feeds; current batch payroll systems may need adaptation" }
    ]
  },

